from board import Board, Piece, Player

def get_move():
    return input("Enter your move (e.g., from-to): ").strip().upper()

def print_board(board):
    board.print_board()

def check_game_state(board, player):
    if board.is_winner(player):
        print(f"Player {player} wins!")
        return True
    if board.is_draw():
        print("Game is a draw!")
        return True
    return False

def main():
    board = Board()
    current_player = Player.WHITE

    while not check_game_state(board, current_player):
        print_board(board)
        move = get_move()
        try:
            board.make_move(current_player, move)
        except ValueError as e:
            print(e)
        else:
            if current_player == Player.WHITE:
                current_player = Player.BLACK
            else:
                current_player = Player.WHITE

if __name__ == "__main__":
    main()
```

